MessagePacket read_header_and_message(const std::span<const uint8_t> buffer) {
    // Create a buffer_adaptor from the input buffer
    hexi::buffer_adaptor adaptor(buffer);

    // Create a binary_stream using the buffer_adaptor
    hexi::binary_stream stream(adaptor);

    // Read the header (uint32_t) from the buffer_adaptor using binary_stream's operator>>
    uint32_t header;
    stream >> header;

    // Read the null-terminated string using binary_stream's view method
    std::string_view message = stream.view();

    // Return a MessagePacket containing the header and the string view
    return MessagePacket{header, message};
}
```

