#include <hexi/pmc/buffer_read_adaptor.h>
#include <hexi/pmc/buffer_write_adaptor.h>
#include <vector>
#include <cstdint>

std::size_t write_multiple_chunks(const std::vector<std::vector<uint8_t>>& chunks) {
    // Create a buffer to store the written data
    std::vector<uint8_t> buffer;

    // Create buffer_write_adaptor instance
    hexi::pmc::buffer_write_adaptor<std::vector<uint8_t>> adaptor(buffer);

    // Write each chunk with space checking
    for (const auto& chunk : chunks) {
        // Check if there's enough space using free()
        if (adaptor.free() < chunk.size()) {
            // If not enough space, resize the buffer manually
            buffer.resize(adaptor.write_ + chunk.size());
        }

        // Write the chunk data using write()
        adaptor.write(chunk.data(), chunk.size());
    }

    // Return the total size written using size()
    return adaptor.size();
}

std::vector<uint8_t> read_partial_data(const std::vector<uint8_t>& buffer, std::size_t chunk_size) {
    // Create a copy of the input buffer to avoid modifying the original
    std::vector<uint8_t> data_copy = buffer;

    // Create buffer_read_adaptor instance
    hexi::pmc::buffer_read_adaptor<std::vector<uint8_t>> adaptor(data_copy);

    std::vector<uint8_t> result;

    // Read data in chunks until buffer is empty
    while (adaptor.size() > 0) {
        // Determine how much to read in this chunk
        std::size_t current_chunk_size = std::min(chunk_size, adaptor.size());

        // Create temporary buffer for reading
        std::vector<uint8_t> temp_chunk(current_chunk_size);

        // Read data using read()
        adaptor.read(temp_chunk.data(), current_chunk_size);

        // Append to result
        result.insert(result.end(), temp_chunk.begin(), temp_chunk.end());
    }

    return result;
}

